+      } else {
+        this.db = await RvfDatabase.create(
+          storagePath,
+          {
+            dimensions: this.dim,
+            metric: rvfMetric,
+            m: this.config.M ?? 16,
+            efConstruction: this.config.efConstruction ?? 200,
+          },
+          rvfBackendType,
+        );
+      }
