+    this.initialized = false;
+    this.cachedCount = 0;
+  }
+
+  // ─── Async VectorBackendAsync interface (native RVF operations) ───
+
+  async insertAsync(id: string, embedding: Float32Array, metadata?: Record<string, unknown>): Promise<void> {
+    this.ensureInitialized();
