+    const results = await this.db.query(queryVec, k, Object.keys(rvfOpts).length > 0 ? rvfOpts : undefined);
+
+    if (this.config.enableStats !== false) {
+      this.stats.searchCount++;
+      this.stats.searchTotalMs += performance.now() - start;
+    }
