+  }
+
+  /** Compact the store (reclaim dead space) */
+  async compact(): Promise<{ segmentsCompacted: number; bytesReclaimed: number }> {
+    this.ensureInitialized();
+    await this.flush();
+    const result = await this.db.compact();
+    this.stats.compactionCount++;
